use entry::main::rust_main as no_axiom_main;

use core::sync::atomic::{AtomicBool, Ordering};

use crate::{cpu::get_hartid, sched::runtime::run_task};

static BOOT_FLAG: AtomicBool = AtomicBool::new(false);

pub fn boot_broadcast() {
    BOOT_FLAG.store(true, Ordering::SeqCst);
}

/// called by [`crate::entry::init::_boot_hart_init`]
/// called by [`crate::entry::init::_other_hart_init`] as well
pub fn rust_main() -> ! {
    while !BOOT_FLAG.load(Ordering::SeqCst) {}
    info!("[kernel] hart {} has been booted", get_hartid());
    loop {
        run_task();
    }
}

use arch::{consts::KERNEL_ADDR_OFFSET, Arch, ArchBoot, ArchInfo, ArchInt, _entry_other_hart};
use driver::probe::{probe_device, realize_device};
use memory::bss::bss_init;
use platform::memory::VALID_PHYS_CPU_MASK;

use crate::{
    config::cpu::CPU_NUM,
    constant::banner::NOAXIOM_BANNER,
    cpu::get_hartid,
    entry::{init_proc::schedule_spawn_with_path, main::boot_broadcast},
    fs::fs_init,
    mm::{
        frame_init,
        heap::heap_init,
        memory_set::{kernel_space_activate, kernel_space_init},
    },
    sched::utils::block_on,
    time::clock::ktime_init,
    utils::log::log_init,
};

/// awake other core
#[allow(unused)]
pub fn wake_other_hart(forbid_hart_id: usize) {
    let entry = (_entry_other_hart as usize) & (!KERNEL_ADDR_OFFSET);
    info!(
        "awake_other_hart, forbid hart: {}, entry: {:#x}",
        forbid_hart_id, entry
    );
    for i in 0..CPU_NUM {
        if i != forbid_hart_id && (1 << i) & VALID_PHYS_CPU_MASK != 0 {
            Arch::hart_start(i, entry);
        }
    }
}

#[no_mangle]
pub extern "C" fn _other_hart_init(hart_id: usize, dtb: usize) -> ! {
    Arch::arch_init();
    kernel_space_activate();
    // register_to_hart(); // todo: add multipule devices interrupt support
    info!(
        "[other_init] entry init hart_id: {}, dtb_addr: {:#x}",
        hart_id, dtb as usize,
    );
    Arch::enable_interrupt();
    crate::no_axiom_main()
}

fn hello_world() {
    println!("{}", NOAXIOM_BANNER);
    println!("\u{1B}[1;34m=============================================\u{1B}[0m\n");
    #[cfg(feature = "multicore")]
    println!(
        "[kernel] MULTICORE: CPU_NUM = {}, BOOT_HART = {}",
        CPU_NUM,
        get_hartid()
    );
    #[cfg(not(feature = "multicore"))]
    println!(
        "[kernel] SINGLECORE: CPU_NUM = {}, BOOT_HART = {}",
        CPU_NUM,
        get_hartid()
    );
    println!("[kernel] ARCH = {}", Arch::ARCH_NAME);
}

#[no_mangle]
pub extern "C" fn _boot_hart_init(_: usize, dtb: usize) -> ! {
    bss_init();
    heap_init();

    // log init
    Arch::arch_init();
    log_init();

    // print basic info
    hello_world();

    // kernel space init
    frame_init();
    kernel_space_init();

    // device init
    probe_device(dtb);
    realize_device();

    // fs init
    block_on(fs_init());

    // spawn init_proc and wake other harts
    ktime_init();
    schedule_spawn_with_path();
    #[cfg(feature = "multicore")]
    wake_other_hart(get_hartid());

    // start task runner
    boot_broadcast();
    crate::no_axiom_main()
}

use crate::{
    fs::path::kcreate,
    include::fs::{FileFlags, InodeMode, ALL_PERMISSIONS_MASK},
    mm::memory_set::MemorySet,
    sched::spawn::{spawn_ktask, spawn_utask},
    task::Task,
};

core::arch::global_asm!(include_str!("../link_apps.S"));

/// spawn init process
#[allow(unused)]
pub fn schedule_spawn_with_path() {
    println!("[kernel] INIT_PROC: {}", INIT_PROC_NAME);
    spawn_ktask(async move {
        let path_str = format!("/{}", INIT_PROC_NAME);
        let dentry = kcreate(
            &path_str,
            InodeMode::FILE | InodeMode::from_bits(ALL_PERMISSIONS_MASK).unwrap(),
        );
        let file = dentry.open(&FileFlags::O_RDWR).unwrap();
        let content = get_content(INIT_PROC_NAME);
        file.write_at(0, content).await.unwrap();
        #[cfg(feature = "debug_sig")]
        {
            let mut read_buf = vec![0u8; content.len()];
            let read_size = file.read_at(0, &mut read_buf).await.unwrap();
            assert_eq!(read_buf, content);
        }
        let elf = MemorySet::load_elf(&file).await.unwrap();
        let task = Task::new_init_process(elf).await;
        spawn_utask(&task);
    });
}

macro_rules! use_apps {
    ($($name:literal),+ $(,)?) => {
        $(
            paste::paste! {
            extern "C" {
                #[link_name = concat!($name, "_start")]
                fn [<$name _start>]();
                #[link_name = concat!($name, "_end")]
                fn [<$name _end>]();
            }

            fn [<$name _get_content>]() -> &'static [u8] {
                let start = [<$name _start>] as usize;
                let end = [<$name _end>] as usize;
                let size = end - start;
                debug!(
                    "[kernel_app] start: {:#x}, end: {:#x}, size: {}",
                    start, end, size
                );
                unsafe { core::slice::from_raw_parts(start as *const u8, size) }
            }
        }
        )+
        pub const FINAL_TESTS: &[&str] = &[$($name),+];
    };
}

macro_rules! gen_get_content {
    ($($name:literal),+ $(,)?) => {
        fn get_content(name: &str) -> &'static [u8] {
            match name {
                $(
                    $name => paste::paste! { [<$name _get_content>]() },
                )+
                _ => panic!("Unknown app name: {}", name),
            }
        }
    };
}

#[cfg(feature = "busybox")]
pub const INIT_PROC_NAME: &'static str = "run_busybox";

#[cfg(feature = "runtests")]
pub const INIT_PROC_NAME: &'static str = "run_tests";

use_apps!("run_busybox", "run_tests",);
gen_get_content!("run_busybox", "run_tests");

pub mod init;
pub mod init_proc;
pub mod main;

//! # async task schedule
//! ## usages
//! - [`executor`] provides general executor for all types of async tasks
//! - [`scheduler`] provides scheduler for async tasks, usually we use CFS
//! - [`utils`] contains useful func for async tasks execution

pub mod runtime;
pub mod sched_entity;
pub mod scheduler;
pub mod spawn;
pub mod utils;
pub mod vsched;

use alloc::{collections::vec_deque::VecDeque, sync::Arc};
use core::time::Duration;

use arch::{Arch, ArchInt};
use async_task::{Builder, Runnable, WithInfo};
use config::task::INIT_PROCESS_ID;
use ksync::mutex::SpinLock;
use lazy_static::lazy_static;

use super::{
    sched_entity::SchedMetadata,
    scheduler::{Info, MultiLevelScheduler},
    vsched::{Runtime, Scheduler},
};
use crate::{
    task::Task,
    time::{
        time_slice::{set_next_trigger, TimeSliceInfo},
        timer::timer_handler,
    },
};

type SchedulerImpl = MultiLevelScheduler;
pub struct MultiLevelRuntime {
    scheduler: SpinLock<SchedulerImpl>,
}

impl Runtime<Info> for MultiLevelRuntime {
    fn new() -> Self {
        Self {
            scheduler: SpinLock::new(SchedulerImpl::new()),
        }
    }
    fn run(&self) {
        let runnable = self.scheduler.lock().pop();
        if let Some(runnable) = runnable {
            set_next_trigger(None);
            runnable.run();
        }
    }
    fn schedule(&self, runnable: Runnable<Info>, info: async_task::ScheduleInfo) {
        self.scheduler.lock().push(runnable, info);
    }
    fn spawn<F>(self: &'static Self, future: F, task: Option<&Arc<Task>>)
    where
        F: core::future::Future<Output: Send + 'static> + Send + 'static,
    {
        let metadata = task
            .map(|task| SchedMetadata::from_task(task))
            .unwrap_or_else(SchedMetadata::default);
        let (runnable, handle) = Builder::new().metadata(metadata).spawn(
            move |_| future,
            WithInfo(move |runnable, info| self.schedule(runnable, info)),
        );
        runnable.schedule();
        handle.detach();
    }
}

impl MultiLevelRuntime {
    #[deprecated(note = "use RUNTIME.run() instead")]
    #[allow(dead_code)]
    pub fn handle_realtime(&self) {
        let mut sched = self.scheduler.lock();
        let mut tasks = VecDeque::new();
        while let Some(task) = sched.pop_realtime() {
            tasks.push_back(task);
        }
        drop(sched);
        assert_no_lock!();
        for task in tasks {
            set_next_trigger(Some(TimeSliceInfo::realtime()));
            task.run();
        }
    }
}

type RuntimeImpl = MultiLevelRuntime;
lazy_static! {
    pub static ref RUNTIME: RuntimeImpl = RuntimeImpl::new();
}

#[allow(unused)]
fn debug() {
    use crate::utils::crossover::intermit;
    intermit(Some(10000000), Some(Duration::from_millis(500)), || {
        memory::utils::print_mem_info();
        if let Some(manager) = crate::task::manager::TASK_MANAGER.0.try_lock() {
            for (id, task) in manager.iter() {
                if let Some(task) = task.upgrade() {
                    assert!(task.tid() == *id);
                    let pcb = task.pcb();
                    warn!(
                                "[main] tid{} in {:?}, pending_sig: {:?}, pending_set: {}, should_wake: {}, mask: {}",
                                task.tid(),
                                task.tcb().current_syscall,
                                pcb.signals
                                    .queue
                                    .iter()
                                    .map(|s| s.signal)
                                    .collect::<alloc::vec::Vec<_>>(),
                                pcb.signals.pending_set.debug_info_short(),
                                pcb.signals.should_wake.debug_info_short(),
                                task.sig_mask().debug_info_short(),
                            );
                } else {
                    error!("[main] tid{} NOT FOUND!!!", id);
                }
            }
        } else {
            error!("[main] task manager got locked!");
        }
        if let Some(init_proc) = crate::task::manager::TASK_MANAGER.get(INIT_PROCESS_ID) {
            init_proc.print_child_tree();
        }
    });
}

/// run_tasks: only act as a task runner
#[no_mangle]
pub fn run_task() {
    timer_handler();
    // todo: can we improve the following interrupt check code?
    Arch::enable_interrupt();
    Arch::enable_external_interrupt();
    #[cfg(feature = "debug_sig")]
    debug();
    RUNTIME.run();
}

use alloc::sync::Arc;
use core::future::Future;

use async_task::{Runnable, ScheduleInfo};

use crate::task::Task;

pub trait Scheduler<R> {
    fn new() -> Self;
    fn push(&mut self, runnable: Runnable<R>, info: ScheduleInfo);
    fn pop(&mut self) -> Option<Runnable<R>>;
}

pub trait Runtime<R> {
    fn new() -> Self;
    fn run(&self);
    fn schedule(&self, runnable: Runnable<R>, info: ScheduleInfo);
    fn spawn<F>(self: &'static Self, future: F, task: Option<&Arc<Task>>)
    where
        F: Future<Output: Send + 'static> + Send + 'static;
}

use alloc::collections::vec_deque::VecDeque;

use async_task::Runnable;
use ksync::cell::SyncUnsafeCell;

use super::{
    sched_entity::{SchedMetadata, SchedPrio},
    vsched::Scheduler,
};

pub(super) type Info = SchedMetadata;

struct FifoScheduler {
    queue: VecDeque<Runnable<Info>>,
}

impl Scheduler<Info> for FifoScheduler {
    fn new() -> Self {
        Self {
            queue: VecDeque::new(),
        }
    }
    fn push(&mut self, runnable: Runnable<Info>, _: async_task::ScheduleInfo) {
        self.queue.push_back(runnable);
    }
    fn pop(&mut self) -> Option<Runnable<Info>> {
        self.queue.pop_front()
    }
}

pub struct DualPrioScheduler {
    normal: FifoScheduler,
    idle: FifoScheduler,
}

impl Scheduler<Info> for DualPrioScheduler {
    fn new() -> Self {
        Self {
            normal: FifoScheduler::new(),
            idle: FifoScheduler::new(),
        }
    }
    fn push(&mut self, runnable: Runnable<Info>, info: async_task::ScheduleInfo) {
        match info.woken_while_running {
            true => self.idle.push(runnable, info),
            false => self.normal.push(runnable, info),
        }
    }
    fn pop(&mut self) -> Option<Runnable<Info>> {
        if let Some(runnable) = self.normal.pop() {
            return Some(runnable);
        }
        self.idle.pop()
    }
}

type ExpiredSchedulerInnerImpl = DualPrioScheduler;
pub struct ExpiredScheduler {
    current: SyncUnsafeCell<ExpiredSchedulerInnerImpl>,
    expire: SyncUnsafeCell<ExpiredSchedulerInnerImpl>,
}

impl ExpiredScheduler {
    fn switch_expire(&mut self) {
        core::mem::swap(&mut self.current, &mut self.expire);
    }
}

impl Scheduler<Info> for ExpiredScheduler {
    fn new() -> Self {
        Self {
            current: SyncUnsafeCell::new(ExpiredSchedulerInnerImpl::new()),
            expire: SyncUnsafeCell::new(ExpiredSchedulerInnerImpl::new()),
        }
    }
    fn push(&mut self, runnable: Runnable<Info>, info: async_task::ScheduleInfo) {
        self.expire.as_ref_mut().push(runnable, info);
    }
    fn pop(&mut self) -> Option<Runnable<Info>> {
        let current = self.current.as_ref_mut();
        let res = current.pop();
        if let None = res.as_ref() {
            self.switch_expire();
            self.current.as_ref_mut().pop()
        } else {
            res
        }
    }
}

type RealTimeSchedulerImpl = FifoScheduler;
type NormalSchedulerImpl = ExpiredScheduler;
#[repr(align(64))]
pub struct MultiLevelScheduler {
    realtime: RealTimeSchedulerImpl,
    normal: NormalSchedulerImpl,
}

impl Scheduler<Info> for MultiLevelScheduler {
    fn new() -> Self {
        Self {
            realtime: RealTimeSchedulerImpl::new(),
            normal: NormalSchedulerImpl::new(),
        }
    }
    fn push(&mut self, runnable: Runnable<Info>, info: async_task::ScheduleInfo) {
        let entity = runnable.metadata().sched_entity();
        if let Some(entity) = entity {
            match entity.sched_prio {
                SchedPrio::RealTime(_) => self.realtime.push(runnable, info),
                _ => self.normal.push(runnable, info),
            }
        } else {
            self.realtime.push(runnable, info);
        }
    }
    fn pop(&mut self) -> Option<Runnable<Info>> {
        if let Some(runnable) = self.realtime.pop() {
            return Some(runnable);
        }
        self.normal.pop()
    }
}

impl MultiLevelScheduler {
    pub fn pop_realtime(&mut self) -> Option<Runnable<Info>> {
        self.realtime.pop()
    }
}

