    /// create and initialize the process's proc/{tid} path
    pub fn set_dir_proc(tid: usize) -> Arc<dyn Dentry> {
        let ret = kcreate(
            &format!("/proc/{}", tid),
            InodeMode::DIR | InodeMode::from_bits(0o755).unwrap(),
        );

        // /proc/<pid>/status
        let status = Arc::new(StatusDentry::new(
            Some(ret.clone()),
            "status",
            ret.super_block(),
        ));
        let statinode = Arc::new(StatusInode::new(ret.super_block()));
        status.into_dyn().set_inode(statinode);
        ret.add_child(status);

        // /proc/<pid>/stat
        let stat = Arc::new(ProcStatDentry::new(
            Some(ret.clone()),
            "stat",
            ret.super_block(),
        ));
        let statinode = Arc::new(ProcStatInode::new(ret.super_block()));
        stat.into_dyn().set_inode(statinode);
        ret.add_child(stat);

        ret
    }

    /// delete the process's proc/{tid} path
    pub fn del_dir_proc(tid: usize) {
        kdelete(&format!("/proc/{}", tid));
    }

