        let user_stack_top = user_stack_base + USER_STACK_SIZE; // stack top
        let map_area = MapArea::new(
            user_stack_base,
            user_stack_base + USER_STACK_SIZE,
            MapType::Framed,
            map_permission!(U, R, W),
            MapAreaType::UserStack,
        )?;
        memory_set.stack = map_area;
        info!(
