/// split a path string into components
/// just string operation
///
/// return the components as a vector of strings
pub fn resolve_path(path: &str) -> SysResult<Vec<&str>> {
    let paths = path
        .split('/')
        .filter(|s| !s.is_empty())
        .collect::<Vec<&str>>();
    for path in &paths {
        if path.len() > MAX_NAME_LEN {
            return Err(Errno::ENAMETOOLONG);
        }
    }
    Ok(paths)
}

