}

impl Cpu {
    pub const fn new() -> Self {
        Self {
            task: None,
            ktrap_depth: 0,
        }
    }
    pub fn add_trap_depth(&mut self) {
        self.ktrap_depth += 1;
        if self.ktrap_depth > 2 {
